"""Restore file-level docstrings/headers stripped by the comment-cleanup pass.

For every working-tree-modified .py/.ts/.tsx file, compute the leading
"preamble" (the maximal run of blank lines, line/block comments, module
docstrings, and JS directives before the first import/code line). If HEAD's
preamble differs from the working tree's, restore HEAD's preamble while keeping
the rest of the file (so function-docstring and inline-comment removals stay).
"""

import subprocess
import sys

DRY = "--write" not in sys.argv


def sh(args: list[str]) -> subprocess.CompletedProcess:
    return subprocess.run(args, capture_output=True, text=True)


def changed_files() -> list[str]:
    out = sh(["git", "diff", "HEAD", "--name-only"]).stdout.split()
    return [f for f in out if f.endswith((".py", ".ts", ".tsx"))]


def head_text(path: str) -> str | None:
    r = sh(["git", "show", f"HEAD:{path}"])
    return r.stdout if r.returncode == 0 else None


def split_py(text: str) -> tuple[str, str]:
    lines = text.splitlines(keepends=True)
    i, n = 0, len(lines)
    while i < n:
        s = lines[i].strip()
        if s == "" or s.startswith("#"):
            i += 1
            continue
        if s.startswith('"""') or s.startswith("'''"):
            q = s[:3]
            body = s[3:]
            if body.endswith(q) and len(body) >= 3:  # single-line docstring
                i += 1
                continue
            i += 1
            while i < n and q not in lines[i]:
                i += 1
            if i < n:
                i += 1
            continue
        break
    return "".join(lines[:i]), "".join(lines[i:])


def split_ts(text: str) -> tuple[str, str]:
    directives = {
        '"use client";', "'use client';", '"use server";', "'use server';",
        '"use client"', "'use client'", '"use server"', "'use server'",
    }
    lines = text.splitlines(keepends=True)
    i, n = 0, len(lines)
    while i < n:
        s = lines[i].strip()
        if s == "" or s.startswith("//") or s in directives:
            i += 1
            continue
        if s.startswith("/*"):
            if "*/" in s:
                i += 1
                continue
            i += 1
            while i < n and "*/" not in lines[i]:
                i += 1
            if i < n:
                i += 1
            continue
        break
    return "".join(lines[:i]), "".join(lines[i:])


def main() -> None:
    changed = 0
    for f in changed_files():
        head = head_text(f)
        if head is None:
            continue
        with open(f) as fh:
            work = fh.read()
        split = split_py if f.endswith(".py") else split_ts
        hp, _ = split(head)
        wp, wr = split(work)
        if hp == wp:
            continue
        new = hp + wr
        if new == work:
            continue
        changed += 1
        print(f"\n=== {f} ===")
        print(f"  HEAD preamble ({hp.count(chr(10))} lines) -> working preamble ({wp.count(chr(10))} lines)")
        if DRY:
            print("  [dry-run] would restore HEAD preamble")
        else:
            with open(f, "w") as fh:
                fh.write(new)
            print("  restored")
    print(f"\n{'Would restore' if DRY else 'Restored'} {changed} file(s).")


if __name__ == "__main__":
    main()

