"""Verify the comment cleanup changed ONLY comments/docstrings, never real code.

Python: parse HEAD and working versions, strip every docstring node, then
compare the AST dumps. Comments are absent from the AST already, so if the
docstring-stripped ASTs are identical, no executable code changed.

TS/TSX: grep removed (`-`) diff lines for code keywords that are not comments;
biome already validates references, this catches accidental code deletion.
"""

import ast
import subprocess


def sh(args: list[str]) -> subprocess.CompletedProcess:
    return subprocess.run(args, capture_output=True, text=True)


def strip_docstrings(tree: ast.AST) -> ast.AST:
    for node in ast.walk(tree):
        if isinstance(node, (ast.Module, ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            body = node.body
            if (
                body
                and isinstance(body[0], ast.Expr)
                and isinstance(body[0].value, ast.Constant)
                and isinstance(body[0].value.value, str)
            ):
                node.body = body[1:]
    return tree


def py_skeleton(src: str) -> str:
    return ast.dump(strip_docstrings(ast.parse(src)))


changed = sh(["git", "diff", "HEAD", "--name-only"]).stdout.split()
py = [f for f in changed if f.endswith(".py")]
ts = [f for f in changed if f.endswith((".ts", ".tsx"))]

print(f"Checking {len(py)} python + {len(ts)} ts/tsx files\n")

py_bad = []
for f in py:
    head = sh(["git", "show", f"HEAD:{f}"]).stdout
    with open(f) as fh:
        work = fh.read()
    try:
        if py_skeleton(head) != py_skeleton(work):
            py_bad.append(f)
    except SyntaxError as e:
        py_bad.append(f"{f} (syntax: {e})")

print("PYTHON: code skeleton changed in:" if py_bad else "PYTHON: no executable code changed in any file ✔")
for f in py_bad:
    print("  !!", f)

# TS: look for removed code lines (not comment/blank) in the diff
KW = ("import ", "export ", "const ", "let ", "var ", "function ", "return ", "=>", "interface ", "type ", "class ", "enum ")
diff = sh(["git", "diff", "HEAD", "--", "*.ts", "*.tsx"]).stdout.splitlines()
suspicious = []
for line in diff:
    if not line.startswith("-") or line.startswith("---"):
        continue
    body = line[1:].strip()
    if not body or body.startswith(("//", "/*", "*", "*/")):
        continue
    if any(k in body for k in KW):
        suspicious.append(body)

print("\nTS: removed non-comment lines containing code keywords:" if suspicious else "\nTS: no code-bearing lines removed (only comments) ✔")
for s in suspicious[:40]:
    print("  -", s)
print(f"\n  total suspicious TS lines: {len(suspicious)}")

